import{_ as a,o as t,c as o,a3 as c}from"./chunks/framework.aYYe0dfI.js";const u=JSON.parse('{"title":"Module extract","description":"The extract module is responsible for orchestrating the asynchronous extraction of project data, including symbols, modules, and dependency graphs. It manages the entire extraction pipeline: loading and validating scan and AST caches, building module information from scan results, constructing dependency graphs, and persisting extraction outputs back into cache records. The public-facing interface is limited to the entry point clore::extract::extract_project_async, which initiates non‑blocking extraction given a project identifier and event loop.","frontmatter":{"title":"Module extract","description":"The extract module is responsible for orchestrating the asynchronous extraction of project data, including symbols, modules, and dependency graphs. It manages the entire extraction pipeline: loading and validating scan and AST caches, building module information from scan results, constructing dependency graphs, and persisting extraction outputs back into cache records. The public-facing interface is limited to the entry point clore::extract::extract_project_async, which initiates non‑blocking extraction given a project identifier and event loop.","layout":"doc","template":"doc"},"headers":[],"relativePath":"clore/modules/extract/index.md","filePath":"en/clore/modules/extract/index.md"}'),r={name:"clore/modules/extract/index.md"};function i(n,e,d,s,l,h){return t(),o("div",null,[...e[0]||(e[0]=[c('<h1 id="module-extract" tabindex="-1">Module <code>extract</code> <a class="header-anchor" href="#module-extract" aria-label="Permalink to &quot;Module `extract`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p>The <code>extract</code> module is responsible for orchestrating the asynchronous extraction of project data, including symbols, modules, and dependency graphs. It manages the entire extraction pipeline: loading and validating scan and AST caches, building module information from scan results, constructing dependency graphs, and persisting extraction outputs back into cache records. The public-facing interface is limited to the entry point <code>clore::extract::extract_project_async</code>, which initiates non‑blocking extraction given a project identifier and event loop.</p><p>Internally, the module owns parallel AST batch extraction (<code>extract_ast_batch_async</code>, <code>extract_ast_entry</code>), cache I/O operations (loading and saving both extract and clice caches), and data structures such as <code>ParallelASTResult</code>, <code>LoadedCaches</code>, <code>CacheEvaluation</code>, and <code>ExtractError</code> that track extraction state and cache validity. It also provides utility helpers for computing module grouping, dependency ordering, and timing metrics, all within the <code>clore::extract</code> namespace.</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./../config/"><code>config</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./../agent/"><code>agent</code></a></li><li><a href="./../agent/tools"><code>agent:tools</code></a></li><li><a href="./../generate/"><code>generate</code></a></li><li><a href="./../generate/analysis"><code>generate:analysis</code></a></li><li><a href="./../generate/common"><code>generate:common</code></a></li><li><a href="./../generate/diagram"><code>generate:diagram</code></a></li><li><a href="./../generate/dryrun"><code>generate:dryrun</code></a></li><li><a href="./../generate/evidence"><code>generate:evidence</code></a></li><li><a href="./../generate/"><code>generate:evidence_builder</code></a></li><li><a href="./../generate/model"><code>generate:model</code></a></li><li><a href="./../generate/page"><code>generate:page</code></a></li><li><a href="./../generate/planner"><code>generate:planner</code></a></li><li><a href="./../generate/scheduler"><code>generate:scheduler</code></a></li><li><a href="./../generate/symbol"><code>generate:symbol</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-extracterror" tabindex="-1"><code>clore::extract::ExtractError</code> <a class="header-anchor" href="#clore-extract-extracterror" aria-label="Permalink to &quot;`clore::extract::ExtractError`&quot;">​</a></h3><p>Declaration: <code>extract/extract.cppm:21</code></p><p>Definition: <code>extract/extract.cppm:21</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The <code>clore::extract::ExtractError</code> struct is a lightweight error type designed to carry a descriptive error message. Its only data member is <code>message</code>, a <code>std::string</code> that stores the textual description of the failure. There are no other fields, invariants, or complex member functions; the struct serves as a simple, self-contained error representation that can be constructed, inspected, and propagated as needed within the extraction logic. The absence of additional state keeps the type trivial to manage and ensures that the error message is the sole source of diagnostic information.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>No invariants beyond the validity of the underlying <code>std::string</code></li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code></li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Thrown or returned by extraction functions to indicate failure</li><li>Caught or inspected by callers to obtain an error description</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-extract-project-async" tabindex="-1"><code>clore::extract::extract_project_async</code> <a class="header-anchor" href="#clore-extract-extract-project-async" aria-label="Permalink to &quot;`clore::extract::extract_project_async`&quot;">​</a></h3><p>Declaration: <code>extract/extract.cppm:25</code></p><p>Definition: <code>extract/extract.cppm:539</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The implementation of <code>clore::extract::extract_project_async</code> proceeds in two main phases. First, it loads and filters the compilation database, then asynchronously loads existing extract and clice caches via <code>load_caches_async</code>. For each entry, it computes a cache key and compile signature, evaluates cache validity (scan and AST) using <code>cache_evaluations</code> and <code>prepared_entries</code>, and builds a dependency graph via <code>build_dependency_graph_async</code> with a topology sort. A batch of parallel AST extractions is launched through <code>extract_ast_batch_async</code>, which either reuses cached AST results or invokes fresh extraction.</p><p>In the second phase, the function iterates over all filtered entries sequentially. For each entry, it either retrieves the cached AST or takes the parallel result, then resolves symbol declaration and definition file paths using <code>resolve_symbol_location_path</code>, which delegates to <code>run_worker_task_async</code> for worker‑isolation. Symbols and includes are filtered against the given <code>config.filter</code> and <code>filter_root</code>, merged into the <code>ProjectModel</code>, and relations (inheritance, calls, references) are linked. Cache records are updated after each file. After all files are processed, the function rebuilds model indexes, constructs module info via <code>build_module_info</code>, and asynchronously resolves source snippets using <code>kota::queue</code>. Caches are persisted at the end via <code>save_caches_async</code>, even on failure (through the <code>fail_after_persist</code> lambda). The final <code>ProjectModel</code> is returned, containing the extracted symbols, files, relations, and timing statistics.</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>reads compilation database file specified in config<code>.compile_commands_path</code></li><li>reads cache files from <code>workspace_root</code> via <code>load_caches_async</code></li><li>writes cache files to <code>workspace_root</code> via <code>save_caches_async</code></li><li>modifies <code>cache_records</code> and <code>clice_cache</code> in memory</li><li>logs extensive timing and statistics information</li><li>may produce errors that are propagated or handled by persisting caches before failing</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>config (<code>TaskConfig</code>) with fields <code>compile_commands_path</code>, <code>workspace_root</code>, filter</li><li>loop (<code>kota::event_loop</code>) for asynchronous operations</li><li>compilation database entries (db<code>.entries</code>)</li><li>cache records loaded from disk (<code>cache_records</code>, <code>clice_cache</code>)</li><li>source files via scan and AST extraction</li><li>file system for path resolution and existence checks</li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>cache_records</code> and <code>clice_cache</code> (in memory, later persisted)</li><li>model (<code>ProjectModel</code>) which is returned and contains symbols, files, namespaces</li><li>log output via <code>logging::info</code> calls</li><li><code>resolved_path_cache</code> (local map for caching path resolutions)</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called as the main extraction function in the clore extraction pipeline</li><li>typically invoked from a command-line tool that provides config and event loop</li><li>used in conjunction with async caching and AST extraction utilities</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p>The extract module is decomposed around a single public entry point, <code>extract_project_async</code>, which orchestrates an asynchronous pipeline for extracting project metadata. Internally, the module is layered into a set of anonymous‑namespace helpers that handle cache I/O (<code>load_caches_async</code>, <code>save_caches_async</code>), parallel AST extraction (<code>extract_ast_batch_async</code>, <code>extract_ast_entry</code>), and module‑info construction (<code>build_module_info</code>). Supporting types such as <code>CacheEvaluation</code>, <code>PreparedEntryState</code>, <code>ParallelASTResult</code>, and <code>LoadedCaches</code> encapsulate cache‑hit/miss state, per‑file preparation, extraction results, and loaded cache records, respectively. The module imports <code>config</code> for settings, <code>support</code> for file I/O, hashing, path normalization, and logging, and <code>std</code> for containers and error propagation. Error handling is centralized through <code>ExtractError</code> and helpers like <code>unexpected_extract_error</code>, while timing variables (e.g., <code>dt_ast</code>, <code>dt_file</code>) reveal internal instrumentation for performance monitoring.</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./../config/">Module config</a></li><li><a href="./../support/">Module support</a></li></ul>',39)])])}const m=a(r,[["render",i]]);export{u as __pageData,m as default};
